class Solution:
    def canMakePalindromeQueries(self, s: str, queries: List[List[int]]) -> List[bool]:
        res = []
        for a, b, c, d in queries:
            left, right = {}, {}
            for i in range(a, b + 1):
                left[s[i]] = left.get(s[i], 0) + 1
            for i in range(c, d + 1):
                right[s[i]] = right.get(s[i], 0) + 1
            odd_count = 0
            for k in left:
                if k in right:
                    odd_count += abs(left[k] - right[k]) % 2
                else:
                    odd_count += left[k] % 2
            for k in right:
                if k not in left:
                    odd_count += right[k] % 2
            res.append(odd_count <= 1)
        return res
